function Container({ children, className }: { children: ReactNode; className?: string }) {
  return <div className={cn("mx-auto w-full max-w-[1180px] px-4 sm:px-6 lg:px-8", className)}>{children}</div>;
}

function Section({ id, className, children }: { id?: string; className?: string; children: ReactNode }) {
  return (
    <section id={id} className={cn("scroll-mt-24 py-14 sm:py-20 lg:py-24", className)}>
      <Container>{children}</Container>
    </section>
  );
}

export function SectionHeading({ eyebrow, title, description, action, centered = false }: { eyebrow?: string; title: string; description?: string; action?: ReactNode; centered?: boolean; }) {
  return (
    <div className={cn("flex flex-col gap-4", centered ? "items-center text-center" : "items-start", action ? "sm:flex-row sm:items-end sm:justify-between" : "") }>
      <div className={centered ? "max-w-3xl" : "max-w-3xl"}>
        {eyebrow ? <p className="mb-3 text-xs font-semibold uppercase tracking-[0.22em] text-[color:var(--primary-dark)]">{eyebrow}</p> : null}
        <h2 className="text-3xl font-semibold tracking-[-0.05em] text-[color:var(--foreground)] sm:text-4xl lg:text-[2.75rem]">{title}</h2>
        {description ? <p className="mt-3 max-w-3xl text-base leading-7 text-[color:var(--muted-foreground)] sm:text-lg">{description}</p> : null}
      </div>
      {action ? <div>{action}</div> : null}
    </div>
  );
}

