function MiniBars({ values, tone = "primary" }: { values: number[]; tone?: "primary" | "warning" | "success"; }) { return <div className="flex h-16 items-end gap-1.5">{values.map((value, index) => <span key={index} className={cn("flex-1 rounded-full motion-safe:animate-wave-bar motion-reduce:animate-none", tone === "warning" ? "bg-[linear-gradient(180deg,rgba(246,200,95,0.95),rgba(245,165,36,0.9))]" : tone === "success" ? "bg-[linear-gradient(180deg,rgba(38,162,105,0.95),rgba(47,143,122,0.9))]" : "bg-[linear-gradient(180deg,rgba(47,143,122,0.95),rgba(139,183,255,0.85))]")} style={{ height: `${Math.max(12, value)}px`, animationDelay: `${index * 65}ms` }} />)}</div>; }

export function FeatureCard({ icon, title, description, visual }: { icon: ReactNode; title: string; description: string; visual?: ReactNode; }) { return <Card className="group h-full overflow-hidden transition duration-300 hover:-translate-y-1 hover:shadow-[0_24px_70px_rgba(16,35,31,0.1)]"><CardHeader><div className="flex items-start justify-between gap-3"><div className="flex h-11 w-11 items-center justify-center rounded-2xl border border-[color:var(--border)] bg-[color:var(--primary-soft)]/70 text-[color:var(--primary-dark)]">{icon}</div><div className="rounded-full border border-[color:var(--border)] bg-[color:var(--background)] px-3 py-1 text-[11px] font-medium uppercase tracking-[0.18em] text-[color:var(--muted-foreground)]">Calm signal</div></div><CardTitle className="text-[1.15rem]">{title}</CardTitle><CardDescription className="text-base leading-7">{description}</CardDescription></CardHeader>{visual ? <CardBody className="pt-0">{visual}</CardBody> : null}</Card>; }

